// pubspec.dev: mocktail: ^1.0.0
import 'package:mocktail/mocktail.dart';
import 'package:flutter_test/flutter_test.dart';

class MockUserApi extends Mock implements UserApi {}

void main() {
  late MockUserApi api;
  late ProfileBloc bloc;

  setUp(() {
    api = MockUserApi();
    bloc = ProfileBloc(api);
  });

  setUpAll(() {
    // Required when stubbing methods with non-nullable args using any()
    registerFallbackValue(const UpdateProfileRequest(name: ''));
  });

  test('updates profile and emits Success', () async {
    when(() => api.update(any())).thenAnswer(
      (_) async => const User(id: 1, name: 'Ada'),
    );

    await bloc.update('Ada');

    verify(() => api.update(any())).called(1);
    expect(bloc.state, isA<Loaded>());
  });

  test('falls through unstubbed methods → returns null/throws', () {
    // mocktail returns null for unstubbed nullable; throws MissingStubError otherwise
    expect(() => api.deleteUser(1), throwsA(isA<MissingStubError>()));
  });
}

// ── Hand-written fake — better when you need behaviour, not just verification ──
class FakeAuthRepo implements AuthRepository {
  bool signedIn = false;
  @override Future<User?> currentUser() async => signedIn ? User(id: 1) : null;
  @override Future<void> signIn(String e, String p) async => signedIn = true;
  @override Future<void> signOut() async => signedIn = false;
}

test('AuthBloc reacts to signOut', () async {
  final repo = FakeAuthRepo()..signedIn = true;
  final bloc = AuthBloc(repo);
  await bloc.signOut();
  expect(bloc.state, isA<Anonymous>());
});

