import 'package:http_mock_adapter/http_mock_adapter.dart';

test('UsersRepo.byId hits correct URL', () async {
  final dio = Dio(BaseOptions(baseUrl: 'https://api.example.com'));
  final adapter = DioAdapter(dio: dio);

  adapter.onGet(
    '/users/42',
    (server) => server.reply(200, {'id': 42, 'name': 'Ada'}),
  );

  final repo = UsersRepo(dio);
  final user = await repo.byId(42);

  expect(user.name, 'Ada');
  // optional: assert request shape
  expect(adapter.history.last.path, '/users/42');
});

